const raw = $input.first();
const content = raw.json.choices?.[0]?.message?.content || '{}';

let selected;
try {
  selected = JSON.parse(content);
} catch(e) {
  const match = content.match(/{[\s\S]*}/);
  selected = match ? JSON.parse(match[0]) : {};
}

const articulos = JSON.parse($('Agregar Noticias').first().json.articulos_json || '[]');
const matched = articulos.find(a => a.hash_titulo === selected.hash_titulo || a.titulo === selected.titulo) || {};

const score = parseFloat(selected.score_relevancia || 0);

return [{ json: {
  titulo: selected.titulo || matched.titulo || '',
  url: selected.url || matched.url || '',
  descripcion: matched.descripcion || '',
  pubDate: matched.pubDate || '',
  hash_titulo: selected.hash_titulo || matched.hash_titulo || '',
  score_relevancia: score,
  razon_seleccion: selected.razon || '',
  continuar: score >= 7
}}];

